# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, abort
from flask_sqlalchemy import SQLAlchemy
from flask_marshmallow import Marshmallow
from flask_login import current_user, LoginManager, UserMixin

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)
ma = Marshmallow(app)
login_manager = LoginManager(app)

class User(db.Model, UserMixin):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(80), unique=True, nullable=False)
    role = db.Column(db.String(20), nullable=False, default='user')  # user/moderator/admin
    account_status = db.Column(db.String(20), nullable=False, default='active')  # active/suspended
    subscription_tier = db.Column(db.String(20), nullable=False, default='free')  # free/pro/enterprise

class UserSchema(ma.SQLAlchemyAutoSchema):
    class Meta:
        model = User
        load_instance = True

user_schema = UserSchema()
users_schema = UserSchema(many=True)

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    if not current_user.is_authenticated or current_user.role != 'admin':
        abort(403, description="Permission denied")

    user = User.query.get_or_404(user_id)
    data = request.get_json()

    allowed_fields = ['email', 'username', 'role', 'account_status', 'subscription_tier']
    for field in allowed_fields:
        if field in data:
            setattr(user, field, data[field])

    db.session.commit()
    return user_schema.jsonify(user)

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))
